import { readFile } from "fs/promises";
import { basename } from "path";
import type { TestResult, TestRun } from "./types";

// Minimal XML tag/attribute extractor -- avoids external dependencies
function getAttr(tag: string, attr: string): string {
  const re = new RegExp(`${attr}\\s*=\\s*"([^"]*)"`, "i");
  const m = tag.match(re);
  return m ? m[1] : "";
}

function extractTags(xml: string, tagName: string): string[] {
  const results: string[] = [];
  const openRe = new RegExp(`<${tagName}[\\s>]`, "gi");
  let match: RegExpExecArray | null;
  while ((match = openRe.exec(xml)) !== null) {
    const start = match.index;
    // Self-closing tag
    const selfClose = xml.indexOf("/>", start);
    const childOpen = xml.indexOf(">", start);
    if (selfClose !== -1 && selfClose < childOpen + 1) {
      results.push(xml.slice(start, selfClose + 2));
    } else {
      const closeTag = `</${tagName}>`;
      const end = xml.indexOf(closeTag, start);
      if (end !== -1) {
        results.push(xml.slice(start, end + closeTag.length));
      }
    }
  }
  return results;
}

export function parseJUnitXML(xml: string, source: string): TestRun {
  const results: TestResult[] = [];
  const suites = extractTags(xml, "testsuite");

  for (const suite of suites) {
    const suiteName = getAttr(suite, "name");
    const cases = extractTags(suite, "testcase");

    for (const tc of cases) {
      const name = getAttr(tc, "name");
      const duration = parseFloat(getAttr(tc, "time") || "0");

      let status: TestResult["status"] = "passed";
      let error: string | undefined;

      if (tc.includes("<failure")) {
        status = "failed";
        const msgMatch = tc.match(/<failure[^>]*message="([^"]*)"/);
        error = msgMatch ? msgMatch[1] : "Unknown failure";
      } else if (tc.includes("<skipped")) {
        status = "skipped";
      }

      results.push({ name, suite: suiteName, status, duration, error });
    }
  }

  return { source, results };
}

interface JSONTestEntry {
  name: string;
  status: "passed" | "failed" | "skipped";
  duration: number;
  error?: string;
}

interface JSONTestSuite {
  name: string;
  tests: JSONTestEntry[];
}

interface JSONTestFile {
  testSuites: JSONTestSuite[];
}

export function parseJSON(json: string, source: string): TestRun {
  const data: JSONTestFile = JSON.parse(json);
  const results: TestResult[] = [];

  for (const suite of data.testSuites) {
    for (const t of suite.tests) {
      results.push({
        name: t.name,
        suite: suite.name,
        status: t.status,
        duration: t.duration,
        error: t.error,
      });
    }
  }

  return { source, results };
}

export async function parseFile(filePath: string): Promise<TestRun> {
  const content = await readFile(filePath, "utf-8");
  const name = basename(filePath);

  if (filePath.endsWith(".xml")) {
    return parseJUnitXML(content, name);
  } else if (filePath.endsWith(".json")) {
    return parseJSON(content, name);
  }

  throw new Error(`Unsupported file format: ${name}`);
}

import { describe, test, expect } from "bun:test";
import { generateMarkdown } from "./markdown";
import type { AggregatedReport } from "./types";

const sampleReport: AggregatedReport = {
  totals: {
    totalTests: 10,
    passed: 7,
    failed: 2,
    skipped: 1,
    duration: 24.345,
  },
  flakyTests: [
    {
      name: "session expires after timeout",
      suite: "AuthTests",
      passedIn: ["run2"],
      failedIn: ["run1"],
    },
  ],
  runs: [
    {
      source: "run1.xml",
      results: [
        {
          name: "login succeeds",
          suite: "AuthTests",
          status: "passed",
          duration: 2.1,
        },
        {
          name: "session expires after timeout",
          suite: "AuthTests",
          status: "failed",
          duration: 4.3,
          error: "Timeout",
        },
      ],
    },
    {
      source: "run2.xml",
      results: [
        {
          name: "login succeeds",
          suite: "AuthTests",
          status: "passed",
          duration: 1.9,
        },
        {
          name: "session expires after timeout",
          suite: "AuthTests",
          status: "passed",
          duration: 4.0,
        },
      ],
    },
  ],
};

describe("generateMarkdown", () => {
  test("includes title header", () => {
    const md = generateMarkdown(sampleReport);
    expect(md).toContain("# Test Results Summary");
  });

  test("includes totals section with correct values", () => {
    const md = generateMarkdown(sampleReport);
    expect(md).toContain("| Total | 10 |");
    expect(md).toContain("| Passed | 7 |");
    expect(md).toContain("| Failed | 2 |");
    expect(md).toContain("| Skipped | 1 |");
    expect(md).toContain("| Duration | 24.35s |");
  });

  test("includes flaky tests section", () => {
    const md = generateMarkdown(sampleReport);
    expect(md).toContain("## Flaky Tests");
    expect(md).toContain("session expires after timeout");
    expect(md).toContain("AuthTests");
  });

  test("includes per-run breakdown", () => {
    const md = generateMarkdown(sampleReport);
    expect(md).toContain("## Per-Run Breakdown");
    expect(md).toContain("run1.xml");
    expect(md).toContain("run2.xml");
  });

  test("shows pass rate", () => {
    const md = generateMarkdown(sampleReport);
    // 7/10 = 70%
    expect(md).toContain("70.0%");
  });

  test("report with no flaky tests says none found", () => {
    const noFlaky: AggregatedReport = {
      totals: {
        totalTests: 5,
        passed: 5,
        failed: 0,
        skipped: 0,
        duration: 3.0,
      },
      flakyTests: [],
      runs: [
        {
          source: "run1",
          results: [
            {
              name: "test1",
              suite: "S",
              status: "passed",
              duration: 1.0,
            },
          ],
        },
      ],
    };
    const md = generateMarkdown(noFlaky);
    expect(md).toContain("No flaky tests detected");
  });
});

