  execSync("git init", { cwd: tmp, stdio: "pipe" });
  execSync('git config user.email "test@test.com"', { cwd: tmp, stdio: "pipe" });
  execSync('git config user.name "Test"', { cwd: tmp, stdio: "pipe" });

  const filesToCopy = [
    "index.ts",
