    if (existsSync(src)) {
      cpSync(src, join(tmp, f));
    }
  }

  cpSync(join(PROJECT_DIR, ".github"), join(tmp, ".github"), {
    recursive: true,
  });

  // Copy only selected fixtures
  execSync("mkdir -p fixtures", { cwd: tmp, stdio: "pipe" });
  for (const f of fixturesToInclude) {
    cpSync(join(PROJECT_DIR, "fixtures", f), join(tmp, "fixtures", f));
  }

