  if (existsSync(join(PROJECT_DIR, "bun.lock"))) {
    cpSync(join(PROJECT_DIR, "bun.lock"), join(tmp, "bun.lock"));
  }

  execSync("git add -A && git commit -m 'init'", {
    cwd: tmp,
    stdio: "pipe",
  });

  return tmp;
}

